int expand_tokens(char **tokens, int m, int *out, int max_n) {
    int n = 0;
    for (int i = 0; i < m; ++i) {
        if (strcmp(tokens[i], "to") == 0 && i > 0 && i + 1 < m) {
            int l = atoi(tokens[i - 1]);
            int r = atoi(tokens[i + 1]);
            for (int v = l + 1; v <= r && n < max_n; ++v) out[n++] = v;
            continue;
        }
        if (i + 1 < m && strcmp(tokens[i + 1], "to") == 0) {
            if (n < max_n) out[n++] = atoi(tokens[i]);
            continue;
        }
        if (i > 0 && strcmp(tokens[i - 1], "to") == 0) continue;
        if (n < max_n) out[n++] = atoi(tokens[i]);
    }
    return n;
}

