typedef struct { int x, y, d; } NodeQ;

int shortest_path(char grid[][64], int n, int m) {
    int qh = 0, qt = 0;
    NodeQ q[4096];
    int vis[64][64] = {0};
    int sx = -1, sy = -1;
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            if (grid[i][j] == 'S') { sx = i; sy = j; }
        }
    }
    q[qt++] = (NodeQ){sx, sy, 0};
    vis[sx][sy] = 1;
    int dx[4] = {1, -1, 0, 0};
    int dy[4] = {0, 0, 1, -1};
    while (qh < qt) {
        NodeQ cur = q[qh++];
        if (grid[cur.x][cur.y] == 'T') return cur.d;
        for (int k = 0; k < 4; ++k) {
            int nx = cur.x + dx[k], ny = cur.y + dy[k];
            if (nx < 0 || nx >= n || ny < 0 || ny >= m) continue;
            if (vis[nx][ny] || grid[nx][ny] == '1') continue;
            vis[nx][ny] = 1;
            q[qt++] = (NodeQ){nx, ny, cur.d + 1};
        }
    }
    return -1;
}

