static int hex_to_int(const char *s, int len) {
    int v = 0;
    for (int i = 0; i < len; ++i) {
        char c = s[i];
        int d = (c <= '9') ? (c - '0') : (c - 'a' + 10);
        v = v * 16 + d;
    }
    return v;
}

int parse_leaf(const char *hex, char *out, int cap) {
    int L = hex_to_int(hex + 4, 8);
    const char *vhex = hex + 12;
    if (L + 1 > cap) return -1;
    for (int i = 0; i < L; ++i) {
        int hi = hex_to_int(vhex + i * 2, 1);
        int lo = hex_to_int(vhex + i * 2 + 1, 1);
        out[i] = (char)(hi * 16 + lo);
    }
    out[L] = '\0';
    return L;
}

