void dfs(int *a,int n,int idx,int remain){
    if(remain==0){record_path();return;}
    for(int i=idx;i<n;i++){
        if(a[i]>remain) break;
        path_push(a[i]);
        dfs(a,n,i,remain-a[i]);
        path_pop();
    }
}

void dfs(int *a,int n,int k){
    if(path_size()==k){record_path();return;}
    for(int i=0;i<n;i++){
        path_push(a[i]);
        dfs(a,n,k);
        path_pop();
    }
}

void dfs(Node *x){
    if(!x) return;
    path_push(x->val);
    if(!x->left && !x->right) record_path();
    dfs(x->left);
    dfs(x->right);
    path_pop();
}

int height(Node *x){
    if(!x) return 0;
    int l=height(x->left), r=height(x->right);
    return (l>r?l:r)+1;
}

int check(Node *x){
    if(!x) return 0;
    int l=check(x->left); if(l==-1) return -1;
    int r=check(x->right); if(r==-1) return -1;
    if(abs(l-r)>1) return -1;
    return (l>r?l:r)+1;
}

